const html = $json.body || $json.data || '';
const cleaned = html
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 18000);

return [{
  json: {
    ...$('Set - Job Input').first().json,
    job_description: cleaned || $('Set - Job Input').first().json.job_description
  }
}];

