const raw = $json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = { subject: '', body: raw };
}

const source = $('Code - Parse Cover Letter').first().json;

return [{
  json: {
    id: `${Date.now()}`,
    date: new Date().toISOString(),
    company: source.company,
    role: source.role,
    job_url: source.job_url,
    input_mode: source.input_mode,
    job_description: source.job_description,
    base_profile_used: source.base_profile_used,
    fit_score: source.fit_score,
    strengths: source.strengths,
    gaps: source.gaps,
    decision: source.decision,
    reasoning: source.reasoning,
    generated_resume: source.generated_resume,
    generated_cover_letter: source.generated_cover_letter,
    generated_email_subject: parsed.subject || '',
    generated_email_body: parsed.body || '',
    ready_for_google_sheets: {
      company: source.company,
      role: source.role,
      job_url: source.job_url,
      base_profile_used: source.base_profile_used,
      fit_score: source.fit_score,
      fit_gaps: JSON.stringify(source.gaps || []),
      decision: source.decision,
      generated_resume: source.generated_resume,
      generated_cover_letter: source.generated_cover_letter,
      generated_email_subject: parsed.subject || '',
      generated_email_body: parsed.body || ''
    }
  }
}];
